INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-36ccc47a-moex-00370', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-111-bf235e6a', 'sub-diplomatic-36ccc47a-05', NULL, 'single_choice', '國際傳播研究出現「去西方化」（de-Westernization）的呼聲。下列有關「去西方化」之敘述，何者 錯誤？', '["「全球媒介事件」（globalmediaevent），像是奧運、世界杯足球賽、奧斯卡頒獎典禮等，證明媒 介全球化是既定事實，而「去西方化」的說法僅是假議題", "主流媒體研究大多以西方媒體為分析對象，許多南方國家的媒體議題並非既有的西方理論可以 適當解釋。因此，在研究上進行「去西方化」的工作更顯重要", "「去西方化」論述強調「打破美國中心論」，起因是美國在國際政治與文化上的強勢地位，主導 了國際傳播議題", "要做到「去西方化」，同時兼顧與國際溝通，就必須重視從在地社會或文化中建立「案例知識」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:26+00:00", "source_pdf_sha1": "162ce7bffd00", "answer_pdf_sha1": "50f8fad25911", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00371', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-111-bf235e6a', 'sub-diplomatic-36ccc47a-05', NULL, 'single_choice', '下列那一個國際組織之總部不是設立於瑞士日內瓦？', '["世界衛生組織", "世界貿易組織", "世界經濟論壇", "世界銀行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:26+00:00", "source_pdf_sha1": "162ce7bffd00", "answer_pdf_sha1": "50f8fad25911", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00372', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-111-bf235e6a', 'sub-diplomatic-36ccc47a-05', NULL, 'single_choice', '歌唱選秀電視形式Idol被許多國家的媒體購買，在當地製作成節目，此一電視節目形式源自 那個國家？', '["美國", "英國", "荷蘭", "比利時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:26+00:00", "source_pdf_sha1": "162ce7bffd00", "answer_pdf_sha1": "50f8fad25911", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00373', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-111-bf235e6a', 'sub-diplomatic-36ccc47a-05', NULL, 'single_choice', '有關中國大陸的「大外宣」，下列敘述何者錯誤？', '["2010年之後，中國大陸開始收購世界各國的中文社群媒體，打造對海外華人的宣傳網", "2010年之後，中國大陸「大外宣」除了透過官媒傳播外，更注重「講好中國故事，傳播好中國 聲音」來行銷軟實力", "2017年，美國國家民主基金會以「銳實力」（sharppower）一詞，說明中共對外輸出的不只是 文化活動、國家形象，更是其專制、威權體制", "所謂「紅色滲透」，是指中國大陸大量收購或投資親中媒體，使得新聞媒體透過自我審查，將有 利中國大陸之意識形態注入新聞內容中"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:26+00:00", "source_pdf_sha1": "162ce7bffd00", "answer_pdf_sha1": "50f8fad25911", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
